#include <stdio.h>

int min(int a, int b) {
    return a < b ? a : b;
}

int main() {
    int n;
    scanf("%d", &n);

    int min1, max1;
    scanf("%d %d", &min1, &max1);

    int min2, max2;
    scanf("%d %d", &min2, &max2);

    int min3, max3;
    scanf("%d %d", &min3, &max3);

    int s1 = min(max1, n - min2 - min3);
    int s2 = min(max2, n - s1 - min3);
    int s3 = n - s1 - s2;

    printf("%d %d %d\n", s1, s2, s3);

    return 0;
}
